mapper.select:
SELECT /* /appform/marketRequest : McpMcpAppformMapper.selectMarketRequest : 오픈마켓 (외부서식지) */ C.PRDT_ID AS RPRS_PRDT_ID , PRDT_NM , PRDT_SCTN_CD , B.SPRT_TP , PLCY_SCTN_CD , A.ORGN_ID AS CNTPNT_SHOP_ID , B.SALE_PLCY_CD AS MODEL_SALE_POLICY_CODE , E.OPER_TYPE , D.PRDT_CODE AS REQ_MODEL_NAME , B.INST_RATE , ( SELECT KT_ORG_ID FROM ORG_ORGN_INFO_MST WHERE 1=1 AND ORGN_ID = #{cntpntShopId} AND ROWNUM = 1 ) AS AGENT_CODE , B.SELF_OPEN_YN , D.PRDT_IND_CD /*제품구분코드 CMN0045*/ FROM MSP_SALE_ORGN_MST A , MSP_SALE_PLCY_MST B , MSP_SALE_PRDT_MST C , CMN_INTM_MDL D , MSP_SALE_OPER_MST E , CMN_GRP_CD_MST F , CMN_HNDST_AMT G WHERE TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') BETWEEN B.SALE_STRT_DTTM AND B.SALE_END_DTTM AND B.CNFM_YN = 'Y' AND A.SALE_PLCY_CD = B.SALE_PLCY_CD AND B.SALE_PLCY_CD = C.SALE_PLCY_CD AND C.PRDT_ID = D.PRDT_ID AND B.SALE_PLCY_CD = E.SALE_PLCY_CD AND A.ORGN_ID = #{cntpntShopId} AND B.SALE_PLCY_CD = #{modelSalePolicyCode} AND D.RPRS_YN = 'Y' AND D.PRDT_DT = '99991231' AND PRDT_IND_CD = F.CD_VAL AND E.OPER_TYPE = #{operType} AND D.PRDT_CODE = #{reqModelName}
AND B.SPRT_TP = #{sprtTp}
and F.GRP_ID = 'CMN0045' AND PRDT_IND_CD = F.CD_VAL AND C.PRDT_ID = G.RPRS_PRDT_ID AND TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') BETWEEN G.UNIT_PRIC_APPL_DTTM AND G.UNIT_PRIC_EXPR_DTTM

SELECT /* /appform/limitForm : McpAppformMapper.selectLimitForm 고객CI정보에 대한 개통 정보 추출 [다회선 제한 기능] */ CONTRACT_NUM, SOC_CODE, SELF_CSTMR_CI FROM ( SELECT T1.CONTRACT_NUM, T4.FST_RATE_CD AS SOC_CODE, T2.SELF_CSTMR_CI FROM ( SELECT REQUEST_KEY, CONTRACT_NUM, ON_OFF_TYPE, SYS_RDATE FROM MCP_REQUEST@DL_MCP WHERE ON_OFF_TYPE IN ('5','7','9','0','3') AND OPER_TYPE = 'NAC3'
AND USIM_KINDS_CD = '09' -- eSIM 신청서
AND NVL(USIM_KINDS_CD,'00') <> '09' -- eSIM 아닌것...
) T1 INNER JOIN (SELECT REQUEST_KEY, SELF_CSTMR_CI FROM MCP_REQUEST_CSTMR@DL_MCP WHERE SELF_CSTMR_CI = #{selfCstmrCi}
AND CSTMR_NAME = #{cstmrName}
) T2 ON T1.REQUEST_KEY = t2.REQUEST_KEY INNER JOIN MSP_JUO_SUB_INFO T3 ON T1.CONTRACT_NUM = t3.CONTRACT_NUM INNER JOIN MSP_REQUEST_DTL T4 ON T3.CONTRACT_NUM = t4.CONTRACT_NUM WHERE 1=1 AND T3.LST_COM_ACTV_DATE > TO_CHAR(SYSDATE-30, 'YYYYMMDD') AND T3.SUB_STATUS <> 'C' ORDER BY T1.SYS_RDATE DESC ) WHERE ROWNUM = 1

SELECT /* /appform/getDisPrmtId : McpAppformMapper.selectDisPrmtId (오프라인) 평생할인 프로모션 아이디 가져오기 */ DISTINCT PRMT_ID FROM VW_DIS_PRMT_DTL A WHERE 1=1 AND TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') BETWEEN A.STRT_DTTM AND A.END_DTTM AND USG_YN = 'Y' AND ORGN_ID = #{cntpntShopId} AND SLS_TP = #{slsTp}
AND INTM_YN = 'N'
AND INTM_YN = 'Y' AND MODEL_ID = (SELECT RPRS_PRDT_ID FROM CMN_INTM_MDL A WHERE PRDT_ID = #{modelId})
/*AND CHNL_TP = 'CS10'*/ AND ENGG_SRL LIKE '%' || #{enggMnthCnt} || '%' AND RATE_CD = #{socCode} AND EVNT_CD = 'NAC'

SELECT /* /appform/mspPrdtCode : McpAppformMapper.selectMspPrdtCode 서식지 관련 MSP 코드 조회 */ (SELECT PRDT_CODE FROM CMN_INTM_MDL WHERE PRDT_ID = T1.RPRS_PRDT_ID) AS REQ_MODEL_NAME , PRDT_COLR_CD AS REQ_MODEL_COLOR , PRDT_NM , PRDT_ID FROM CMN_INTM_MDL T1 WHERE 1=1
AND RPRS_PRDT_ID = #{rprsPrdtId}
AND PRDT_ID = #{modelId} AND ROWNUM =1

mapper.insert:

  SELECT ('AD' || TO_CHAR(SYSDATE,'YYYYMMDD') || TRIM(TO_CHAR(SQ_DIS_AD.NEXTVAL, '000000'))) AS APD_SEQ  FROM DUAL

