, REQ_BUY_TYPE
, REGST_ID
, REGST_DTTM
) VALUES(
#{apdSeq}
, TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
, 'N'
, #{resNo}

  , #{requestKey}


  , #{contractNum}


  , #{prmtId}

, '01'
, #{evntCd}
, '00'
, #{cntpntShopId}
, #{cntpntShopId}
, #{socCode}
, #{onOffType}
, #{operType}
, #{reqBuyType}


    , #{cretId}


    , 'MCP'


, SYSDATE
)
